import type {
  ProgressCompactProps,
  ProgressCompactEmits,
  ProgressCompactSlots,
  ProgressCircleCompactProps,
  ProgressCircleCompactEmits,
  ProgressCircleCompactSlots,
  ProgressUi
} from '@soybeanjs/headless/progress';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeColor, ThemeSize } from '@/theme';

/**
 * Properties for the Progress component.
 */
export interface ProgressProps extends ProgressCompactProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Theme color of the component.
   */
  color?: ThemeColor;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<ProgressUi>;
}

/**
 * Events for the Progress component.
 */
export type ProgressEmits = ProgressCompactEmits;

/**
 * Slots for the Progress component.
 */
export type ProgressSlots = ProgressCompactSlots;

/**
 * Properties for the ProgressCircle component.
 */
export interface ProgressCircleProps extends ProgressCircleCompactProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Theme color of the component.
   */
  color?: ThemeColor;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<ProgressUi>;
}

/**
 * Events for the ProgressCircle component.
 */
export type ProgressCircleEmits = ProgressCircleCompactEmits;

/**
 * Slots for the ProgressCircle component.
 */
export type ProgressCircleSlots = ProgressCircleCompactSlots;

export { progress } from '@soybeanjs/headless/progress';
export { default as SProgressProvider } from './progress-provider.vue';
export { default as SProgress } from './progress.vue';
export { default as SProgressCircle } from './progress-circle.vue';

export type * from '@soybeanjs/headless/progress';
export type * from './types';

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const progressVariants = scv({
  slots: {
    root: 'relative w-full overflow-hidden rounded-full bg-muted',
    indicator: `h-full w-full flex-1 rounded-full transition-[transform,width] duration-300 transform-gpu will-change-transform data-[state=indeterminate]:w-2/5 data-[state=indeterminate]:opacity-80`,
    circle: '',
    track: '',
    label: ''
  },
  variants: {
    color: {
      primary: {
        indicator: 'bg-primary'
      },
      destructive: {
        indicator: 'bg-destructive'
      },
      success: {
        indicator: 'bg-success'
      },
      warning: {
        indicator: 'bg-warning'
      },
      info: {
        indicator: 'bg-info'
      },
      carbon: {
        indicator: 'bg-carbon'
      },
      secondary: {
        indicator: 'bg-secondary-foreground/20'
      },
      accent: {
        indicator: 'bg-accent-foreground/20'
      }
    },
    size: {
      xs: {
        root: 'h-1.5'
      },
      sm: {
        root: 'h-2'
      },
      md: {
        root: 'h-2.5'
      },
      lg: {
        root: 'h-3'
      },
      xl: {
        root: 'h-3.5'
      },
      '2xl': {
        root: 'h-4'
      }
    }
  },
  defaultVariants: {
    color: 'primary',
    size: 'md'
  }
});

export const progressCircleVariants = scv({
  slots: {
    root: 'relative inline-flex shrink-0 items-center justify-center rounded-full',
    indicator: 'fill-none stroke-current transition-[stroke-dasharray,stroke-dashoffset] duration-300 ease-in-out',
    circle: 'size-full',
    track: 'fill-none stroke-current text-muted',
    label: 'pointer-events-none absolute inset-0 flex items-center justify-center'
  },
  variants: {
    color: {
      primary: {
        indicator: 'text-primary'
      },
      destructive: {
        indicator: 'text-destructive'
      },
      success: {
        indicator: 'text-success'
      },
      warning: {
        indicator: 'text-warning'
      },
      info: {
        indicator: 'text-info'
      },
      carbon: {
        indicator: 'text-carbon'
      },
      secondary: {
        indicator: 'text-secondary-foreground/40'
      },
      accent: {
        indicator: 'text-accent-foreground/40'
      }
    },
    size: {
      xs: {
        root: 'h-8 w-8 text-[10px]'
      },
      sm: {
        root: 'h-10 w-10 text-xs'
      },
      md: {
        root: 'h-12 w-12 text-sm'
      },
      lg: {
        root: 'h-16 w-16 text-base'
      },
      xl: {
        root: 'h-20 w-20 text-lg'
      },
      '2xl': {
        root: 'h-24 w-24 text-xl'
      }
    }
  },
  defaultVariants: {
    color: 'primary',
    size: 'md'
  }
});

export const progressProviderVariants = scv({
  slots: {
    root: 'fixed z-99999 w-0 h-0 pointer-events-none',
    indicator: `fixed top-0 start-0 w-full h-0.75 bg-primary`
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
